files.patch:
@@ -55,7 +55,8 @@ format_push_string = "allow"

 [workspace.dependencies]
 # Core async runtime - our custom cancel-correct runtime
-asupersync = { version = "0.2.0" }
+# Keep defaults off to avoid unsafe SIMD paths; enable only required internals.
+asupersync = { version = "0.2.5", default-features = false, features = ["test-internals"] }

 # Serialization
 serde = { version = "1", features = ["derive"] }

@@ -37,7 +37,7 @@ sqlmodel-console = { workspace = true, optional = true }

 # Optional TLS support
 rustls = { version = "0.23", optional = true, default-features = false, features = ["std", "tls12", "ring"] }
-webpki-roots = { version = "0.26", optional = true }
+webpki-roots = { version = "1", optional = true }
 rustls-pemfile = { version = "2.2", optional = true }

 [dev-dependencies]

@@ -515,8 +515,8 @@ mod tests {
         // Override types should be used instead of base types
         assert!(sql.contains("\"price\" DECIMAL(10,2) NOT NULL"));
         assert!(sql.contains("\"sku\" VARCHAR(50) NOT NULL"));
-        // Non-overridden types use sql_type.sql_name()
-        assert!(sql.contains("\"id\" BIGINT"));
+        // Auto-increment single PK embeds as INTEGER PRIMARY KEY (SQLite compat)
+        assert!(sql.contains("\"id\" INTEGER PRIMARY KEY"));
     }

     #[test]
